import{_ as a,o as i,c as l,a0 as t}from"./chunks/framework.Cl79jK2u.js";const p=JSON.parse('{"title":"Cross-Platform Schedule Abstraction","description":"","frontmatter":{},"headers":[],"relativePath":"design/schedule-abstraction.md","filePath":"design/schedule-abstraction.md"}'),o={name:"design/schedule-abstraction.md"};function n(s,e,r,d,c,h){return i(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="cross-platform-schedule-abstraction" tabindex="-1">Cross-Platform Schedule Abstraction <a class="header-anchor" href="#cross-platform-schedule-abstraction" aria-label="Permalink to &quot;Cross-Platform Schedule Abstraction&quot;">​</a></h1><p>Status: implemented, with Linux native backend intentionally deferred</p><p>This note records the shipped schedule architecture behind <code>moxie schedule</code>.</p><h2 id="what-shipped" tabindex="-1">What shipped <a class="header-anchor" href="#what-shipped" aria-label="Permalink to &quot;What shipped&quot;">​</a></h2><p>Moxie now presents one schedule model across platforms while choosing the best available runtime automatically:</p><ul><li>canonical trigger types: <code>at</code>, <code>interval</code>, and <code>calendar</code></li><li>first-class CLI flags: <code>--at</code>, <code>--in</code>, <code>--every</code>, and <code>--cron</code></li><li>portable cron normalization into the canonical calendar model</li><li>automatic backend reconciliation and sync metadata</li><li>native per-user <code>launchd</code> materialization on macOS for supported schedules</li><li>native per-user Task Scheduler materialization on Windows for supported schedules</li><li>in-process fallback on unsupported shapes or native install/update failures</li><li>internal execution entrypoint: <code>moxie schedule fire &lt;id&gt;</code></li></ul><p>Users do not need a separate install or sync step for schedules.</p><h2 id="canonical-model" tabindex="-1">Canonical model <a class="header-anchor" href="#canonical-model" aria-label="Permalink to &quot;Canonical model&quot;">​</a></h2><p>Moxie owns the source of truth for schedules in its own store. Platform schedulers are projections of that model.</p><p>Canonical trigger types:</p><ul><li><code>at</code> — one-shot exact time</li><li><code>interval</code> — every N duration</li><li><code>calendar</code> — recurring schedule expressed as structured calendar fields</li></ul><p>Cron remains a supported input syntax, but it is parsed into the canonical <code>calendar</code> form rather than used as the primary internal representation.</p><h2 id="trigger-semantics" tabindex="-1">Trigger semantics <a class="header-anchor" href="#trigger-semantics" aria-label="Permalink to &quot;Trigger semantics&quot;">​</a></h2><h3 id="at" tabindex="-1"><code>at</code> <a class="header-anchor" href="#at" aria-label="Permalink to &quot;`at`&quot;">​</a></h3><ul><li>one-shot exact time</li><li><code>--in</code> is resolved into an <code>at</code> schedule at creation time</li><li>native backends may self-remove after the schedule fires</li></ul><h3 id="interval" tabindex="-1"><code>interval</code> <a class="header-anchor" href="#interval" aria-label="Permalink to &quot;`interval`&quot;">​</a></h3><ul><li>recurring elapsed-time semantics</li><li>minimum supported portable granularity is 1 minute</li><li>represented canonically as a duration, not a wall-clock calendar pattern</li></ul><h3 id="calendar" tabindex="-1"><code>calendar</code> <a class="header-anchor" href="#calendar" aria-label="Permalink to &quot;`calendar`&quot;">​</a></h3><ul><li>recurring wall-clock semantics in the system local timezone by default</li><li>backed by structured calendar fields internally</li><li><code>--cron</code> is normalized into this model</li></ul><h2 id="cron-handling" tabindex="-1">Cron handling <a class="header-anchor" href="#cron-handling" aria-label="Permalink to &quot;Cron handling&quot;">​</a></h2><p>Moxie accepts the common portable 5-field form:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>minute hour day-of-month month day-of-week</span></span></code></pre></div><p>Portable forms supported canonically:</p><ul><li>exact values</li><li>wildcards</li><li>safe lists and ranges</li><li>named months and weekdays</li><li>safe descriptors such as <code>@daily</code></li></ul><p>Rejected forms:</p><ul><li>step expressions such as <code>*/5</code></li><li>specials such as <code>?</code>, <code>L</code>, <code>W</code>, <code>#</code>, and <code>@reboot</code></li><li>expressions that restrict both day-of-month and day-of-week at once</li></ul><p>The original cron string is preserved for display, while scheduling uses the normalized canonical calendar fields.</p><h2 id="backend-model" tabindex="-1">Backend model <a class="header-anchor" href="#backend-model" aria-label="Permalink to &quot;Backend model&quot;">​</a></h2><p>Platform scheduler integration is an internal detail. Moxie automatically materializes schedules into native backends when available and falls back to the in-process scheduler when not.</p><p>Current behavior:</p><ul><li>macOS: supported schedules materialize into per-user <code>launchd</code> jobs</li><li>Windows: supported schedules materialize into per-user Task Scheduler jobs</li><li>Linux: native timer integration is not implemented yet; fallback remains first-class</li></ul><p>Sync metadata on each schedule records:</p><ul><li><code>managed_by</code></li><li><code>state</code></li><li><code>error</code></li></ul><p>This metadata explains whether the schedule is running natively or via fallback, and why a fallback happened.</p><h2 id="execution-entrypoint" tabindex="-1">Execution entrypoint <a class="header-anchor" href="#execution-entrypoint" aria-label="Permalink to &quot;Execution entrypoint&quot;">​</a></h2><p>Native schedulers invoke:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> schedule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fire</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>That command is internal/operator plumbing. It keeps execution semantics owned by Moxie while letting OS-native schedulers handle wake-up and trigger timing.</p><h2 id="fallback-rules" tabindex="-1">Fallback rules <a class="header-anchor" href="#fallback-rules" aria-label="Permalink to &quot;Fallback rules&quot;">​</a></h2><p>Fallback behavior is intentional, not an error by itself.</p><p>Moxie falls back to the in-process scheduler when:</p><ul><li>the current platform has no native backend</li><li>the trigger shape cannot be translated safely</li><li>native installation or update fails</li></ul><p>Fallbacks remain visible through schedule sync metadata.</p><h2 id="platform-notes" tabindex="-1">Platform notes <a class="header-anchor" href="#platform-notes" aria-label="Permalink to &quot;Platform notes&quot;">​</a></h2><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><p>Supported schedules are projected into <code>launchd</code> automatically.</p><p>Known fallback cases include:</p><ul><li>second-precision one-shots</li><li>one-shots that require explicit year precision <code>launchd</code> cannot preserve</li><li>calendar shapes that do not map cleanly to <code>StartCalendarInterval</code></li></ul><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><p>Supported schedules are projected into Task Scheduler automatically.</p><p>Known fallback cases include:</p><ul><li>intervals longer than 31 days</li><li>calendar schedules without explicit minute and hour values</li><li>month-filtered weekday schedules in portable calendar mode</li><li>schedules that would expand into too many native triggers</li></ul><p>Windows native schedules currently use the current interactive user token.</p><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><p>Linux intentionally remains on the in-process scheduler for now. No Linux native backend work was included in this rollout.</p><h2 id="compatibility-and-migration" tabindex="-1">Compatibility and migration <a class="header-anchor" href="#compatibility-and-migration" aria-label="Permalink to &quot;Compatibility and migration&quot;">​</a></h2><p>The implementation keeps backward-compatible loading for existing schedule files.</p><ul><li>legacy cron-backed schedules are normalized into <code>calendar</code></li><li>additive sync metadata does not break older files</li><li>old schedules continue to run via fallback where needed</li></ul><h2 id="non-goals-for-this-rollout" tabindex="-1">Non-goals for this rollout <a class="header-anchor" href="#non-goals-for-this-rollout" aria-label="Permalink to &quot;Non-goals for this rollout&quot;">​</a></h2><ul><li>no Linux native scheduler backend</li><li>no functional behavior changes beyond docs/help cleanup in the wrap-up pass</li><li>no user-facing schedule install or repair workflow in the happy path</li></ul>',60)])])}const m=a(o,[["render",n]]);export{p as __pageData,m as default};
